form:Form.form:Scripts:
		var modo=0;
var Unidades;

function RefreshButton()
{                

	if (modo==0)
	{ //Modo Consulta
		CtrlEnabled("lvDIA",true);
		CtrlEnabled("lvMES",true);
		CtrlEnabled("ACEPT" ,false);
		CtrlEnabled("CANCEL",false);

		CtrlEnabled("CLEAR"    ,false);
		CtrlEnabled("SEARCH"   ,false);
		CtrlEnabled("OI_PERFIL",false);
		CtrlEnabled("DURACION" ,false);
		CtrlEnabled("OI_UNIDAD",false);
		CtrlEnabled("MSG"      ,false);

		if (Ctrl("lvDIA").RowsCount()==0)	
		{     
		  CtrlEnabled("lvDIA_EDIT",false);
		  CtrlEnabled("lvDIA_DEL" ,false);
		} else
		{
		  CtrlEnabled("lvDIA_EDIT",true);
		  CtrlEnabled("lvDIA_DEL" ,true);
		}
	} else
	{
		CtrlEnabled("lvDIA",false);
		CtrlEnabled("lvMES",false);

		CtrlEnabled("ACEPT" ,true);
		CtrlEnabled("CANCEL",true);

		CtrlEnabled("CLEAR"    ,true);
		CtrlEnabled("SEARCH"   ,true);
		CtrlEnabled("OI_PERFIL",true);
		CtrlEnabled("DURACION" ,true);
		CtrlEnabled("OI_UNIDAD",true);
		CtrlEnabled("MSG"      ,true);
	}
}        

function OnChangePeriodo()
{
	NomadTimeout("ChangePeriodo()",50,"Cargando el Periodo...");
}

function ChangePeriodo()
{
	var str=GetProxy().SQLService().Get(Ctrl("main").getResource("QUERYMES"),'<DATA fecha="'+Ctrl("iter_position").GetXValue()+'" />');
	Ctrl("lvMES").processResult(str);

	str=new NomadXML(str);
	Ctrl("totHoras").SetXValue(str.GetAttr("TotHORAS"));
	Ctrl("totMeses").SetXValue(str.GetAttr("TOTJORNADA"));

	OnChangeDia();
}

function OnClickPrev()
{
	var year =parseInt(Ctrl("iter_position").GetXValue().substr(0,4),10);
	var month=parseInt(Ctrl("iter_position").GetXValue().substr(4,2),10);

	month--; if (month<=0) { month=12; year--; }
	Ctrl("iter_position").SetXValue((year*100+month).toString());

	OnChangePeriodo();
}

function OnClickNext()
{                     
	var year =parseInt(Ctrl("iter_position").GetXValue().substr(0,4),10);
	var month=parseInt(Ctrl("iter_position").GetXValue().substr(4,2),10);

	month++; if (month>=13) { month=1; year++; }
	Ctrl("iter_position").SetXValue((year*100+month).toString());

	OnChangePeriodo();
}

function OnChangeDia()
{                          
	NomadTimeout("ChangeDia()",50,"Cargando el Dia...");
}

function ChangeDia()
{                          

	var str=GetProxy().SQLService().Get(Ctrl("main").getResource("QUERYDIA"),'<DATA fecha="'+Ctrl("lvMES").GetXValue()+'" />');
	Ctrl("lvDIA").processResult(str);   
	OnChangeTrabajo();
}

function OnChangeTrabajo()
{      
	if (Ctrl("lvDIA").RowsCount()>0)
	{                 
		Ctrl("OI_PROY"  ).SetXValue( Ctrl("lvDIA").GetSelectAttrValue("OI_PROY"  ));
		Ctrl("OI_TAREA" ).SetXValue( Ctrl("lvDIA").GetSelectAttrValue("OI_TAREA" ));
		Ctrl("OI_PERFIL").SetXValue( Ctrl("lvDIA").GetSelectAttrValue("OI_PERFIL"));
		Ctrl("DURACION" ).SetXValue( Ctrl("lvDIA").GetSelectAttrValue("DURACION" ));
		Ctrl("OI_UNIDAD").SetXValue( Ctrl("lvDIA").GetSelectAttrValue("OI_UNIDAD"));
		Ctrl("MSG"      ).SetXValue( Ctrl("lvDIA").GetSelectAttrValue("MSG"      ));
	} else
	{
		Ctrl("OI_PROY"  ).SetXValue("");
		Ctrl("OI_TAREA" ).SetXValue("");
		Ctrl("OI_PERFIL").SetXValue("");
		Ctrl("DURACION" ).SetXValue("");
		Ctrl("OI_UNIDAD").SetXValue(""); 
		Ctrl("MSG"      ).SetXValue("");
	}

	RefreshButton();
}

function DelTrabajo()
{
	MyOBJ=new NomadXML(GetProxy().DDOService().Get("NucleusProject.Base.Project.Trabajos.TRABAJO", Ctrl("lvDIA").GetXValue() ));
	MyOBJ.SetAttr("nmd-status","~d,");
	MyOBJ.FirstChild().SetAttr("nmd-status","~d,");
  	GetProxy().DDOService().Set("NucleusProject.Base.Project.Trabajos.TRABAJO", MyOBJ.ToString() );

	modo=0;
 	OnChangePeriodo();
	return true;
}

function EditTrabajo()
{
	modo=1;
	Ctrl("OI_PROY"  ).SetXValue( Ctrl("lvDIA").GetSelectAttrValue("OI_PROY"  ));
	Ctrl("OI_TAREA" ).SetXValue( Ctrl("lvDIA").GetSelectAttrValue("OI_TAREA" ));
	Ctrl("OI_PERFIL").SetXValue( Ctrl("lvDIA").GetSelectAttrValue("OI_PERFIL"));
	Ctrl("DURACION" ).SetXValue( Ctrl("lvDIA").GetSelectAttrValue("DURACION" ));
	Ctrl("OI_UNIDAD").SetXValue( Ctrl("lvDIA").GetSelectAttrValue("OI_UNIDAD"));
	Ctrl("MSG"      ).SetXValue( Ctrl("lvDIA").GetSelectAttrValue("MSG"      ));
	RefreshButton();
}

function AddTrabajo()
{
	modo=2;
	Ctrl("OI_PROY"  ).SetXValue("");
	Ctrl("OI_TAREA" ).SetXValue("");
	Ctrl("OI_PERFIL").SetXValue("");
	Ctrl("DURACION" ).SetXValue("");
	Ctrl("OI_UNIDAD").SetXValue("2"); 
	Ctrl("MSG"      ).SetXValue("");
	RefreshButton();
}

function Cancel()
{       
	modo=0;
	OnChangeTrabajo();
}

function ClearTarea()
{
	Ctrl("OI_PROY"  ).SetXValue("");
	Ctrl("OI_TAREA" ).SetXValue("");
}

function TareaReport()
{
	this.processResult = function(XML)
	{                 
		var myRESULT=new NomadXML(XML);
		Ctrl("OI_TAREA").SetXValue(myRESULT.GetAttr("oi_tarea"));
		Ctrl("OI_PROY" ).SetXValue(myRESULT.GetAttr("oi_proyecto"));
	}
}

function FindTarea()
{                    
	openNewFlowWait("NucleusProject.Base.Project.Tareas.TAREA.guia.flow","trabajo",'<DATA oi_tarea="'+Ctrl("OI_TAREA").GetXValue()+'" />',new TareaReport(),"S");
}

function Accept()
{       
	if (Ctrl("OI_PERFIL").GetXValue()=="")
	{           
		alert("El Perfil es Obligatorio");
		Ctrl('OI_PERFIL').SetFocus();
		return false;
	}             

	if (Ctrl("OI_UNIDAD").GetXValue()=="")
	{           
		alert("La Unidad es Obligatoria");
		Ctrl('OI_UNIDAD').SetFocus();
		return false;
	}             

	if (Ctrl("DURACION").GetXValue()=="")
	{           
		alert("La Duracion es Obligatoria");
		Ctrl('DURACION').SetFocus();
		return false;
	}             

	var total=Ctrl("DURACION").TypedValue()*Unidades.FindElement2("ROW","oi_unidad_tiempo",Ctrl("OI_UNIDAD").GetXValue()).GetAttrInt("e_minutos");
	if (total>10*60)
	{
		alert("La Duraccion Maxima de un Trabajo es de 10 Horas.");
		Ctrl('DURACION').SetFocus();
		return false;
	}
	if (total<0)
	{
		alert("La Duraccion Minima de un Trabajo es de 0 Minutos.");  
		Ctrl('DURACION').SetFocus();
		return false;
	}

	if (Ctrl("MSG").GetXValue()=="")
	{           
		alert("El Mensaje es Obligatorio");
		Ctrl('MSG').SetFocus();
		return false;
	}               

	var MyOBJ;
	if (modo==2)
	{
		MyOBJ=new NomadXML(GetProxy().DDOService().New("NucleusProject.Base.Project.Trabajos.TRABAJO"));
		MyOBJ.FirstChild().SetAttr("f_fecha", Ctrl("lvMES").GetXValue())
	} else
	{
		MyOBJ=new NomadXML(GetProxy().DDOService().Get("NucleusProject.Base.Project.Trabajos.TRABAJO", Ctrl("lvDIA").GetXValue() ));
		MyOBJ.SetAttr("nmd-status","~u,");
		MyOBJ.FirstChild().SetAttr("nmd-status","~u,");
	}

	MyOBJ.FirstChild().SetAttr("e_duracion", Ctrl("DURACION" ).GetXValue());
	MyOBJ.FirstChild().SetAttr("o_mensaje" , Ctrl("MSG" ).GetXValue());
	MyOBJ.FirstChild().FindElement("oi_recurso"      ).SetAttr("value",Unidades.GetAttr("oi_recurso"));
	MyOBJ.FirstChild().FindElement("oi_perfil"       ).SetAttr("value",Ctrl("OI_PERFIL" ).GetXValue());
	MyOBJ.FirstChild().FindElement("oi_tarea"        ).SetAttr("value",Ctrl("OI_TAREA"  ).GetXValue());
	MyOBJ.FirstChild().FindElement("oi_unidad_tiempo").SetAttr("value",Ctrl("OI_UNIDAD" ).GetXValue());
  var result = GetProxy().DDOService().Set("NucleusProject.Base.Project.Trabajos.TRABAJO", MyOBJ.ToString() );

  //se setea en estado "trabajando" la solicitud.-
  np = new NomadProxy("", ut);
	nSQL = np.SQLService();       
	var idSolicitud = nSQL.GetOBJ(Ctrl("main").getResource("GetSolicitud"), result); 	
	if(idSolicitud.id != "0")
	{
		MySOL=new NomadXML(GetProxy().DDOService().Get("NucleusProject.Base.Project.Solicitudes.SOLICITUD", idSolicitud.id ));
		MySOL.SetAttr("nmd-status","~u,");
		MySOL.FirstChild().SetAttr("nmd-status","~u,");
	  MySOL.FirstChild().SetAttr("c_estado", "8");
	  GetProxy().DDOService().Set("NucleusProject.Base.Project.Solicitudes.SOLICITUD", MySOL.ToString() );
  } 
	modo=0;
 	OnChangePeriodo();
	return true;
}

function OnLoad()
{
	Unidades=new NomadXML(GetProxy().SQLService().Get(Ctrl("main").getResource("QUERYUNIDADES"),''));


	Ctrl("iter_position").SetXValue((Now().getFullYear()*100+Now().getMonth()+1).toString());
	Ctrl("lvMES").SetXValue(((Now().getFullYear()*100+Now().getMonth()+1)*100+Now().getDate()).toString());
	OnChangePeriodo();
}
